/**
 * Generate Reducto firewall config.
 *
 * Data source: https://docs.reducto.ai
 *
 * Reducto authenticates with a Bearer token on
 * `https://platform.reducto.ai/...`.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.reducto.ai";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Reducto API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:reducto",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const reductoFirewall = {",
    '  name: "reducto",',
    '  description: "Reducto API",',
    "  placeholders: {",
    `    REDUCTO_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://platform.reducto.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.REDUCTO_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Reducto firewall config...");
  const ts = generateTypeScript();
  writeOutput("reducto", ts, import.meta.dirname);
}
